const input = $input.first().json;
const fileUrl = input.body?.fileUrl;

if (!fileUrl) {
  throw new Error('fileUrl is required');
}

let parsed;
try {
  parsed = new URL(fileUrl);
} catch (error) {
  throw new Error('fileUrl must be a valid URL');
}

if (!['http:', 'https:'].includes(parsed.protocol)) {
  throw new Error('fileUrl must use http or https');
}

const host = parsed.hostname.toLowerCase();
if (host === 'localhost' || host === '0.0.0.0' || host === '::1' || host.endsWith('.local')) {
  throw new Error('Local hostnames are not allowed');
}

if (host.includes(':')) {
  throw new Error('IPv6 literal hosts are not allowed');
}

if (/^\d+\.\d+\.\d+\.\d+$/.test(host)) {
  const [a, b] = host.split('.').map(Number);
  const privateRange =
    a === 10 ||
    a === 127 ||
    (a === 169 && b === 254) ||
    (a === 172 && b >= 16 && b <= 31) ||
    (a === 192 && b === 168) ||
    (a === 100 && b >= 64 && b <= 127) ||
    (a === 198 && (b === 18 || b === 19));

  if (privateRange) {
    throw new Error('Private IP ranges are not allowed');
  }
}

return [{ json: { ...input, validatedFileUrl: parsed.toString() } }];
